function setupMiddleware(app, config) {
  app.use("*", cors({
    origin: config.cors.origin,
    credentials: config.cors.credentials,
    allowMethods: ["GET", "POST", "PUT", "DELETE", "PATCH", "OPTIONS"],
    allowHeaders: ["Content-Type", "Authorization", "x-api-key"]
  }));
  app.use("*", logger());
  app.use("*", async (c2, next) => {
    const clientIp = c2.req.header("x-forwarded-for") || c2.req.header("x-real-ip") || "unknown";
    const isAllowed = rateLimitStore.isAllowed(clientIp, config.rateLimit.windowMs, config.rateLimit.maxRequests);
    if (!isAllowed) {
      return c2.json({
        error: "Rate limit exceeded",
        message: `Too many requests from ${clientIp}. Please try again later.`
      }, 429);
    }
    await next();
  });
  if (config.auth.enabled) {
    app.use("/api/*", async (c2, next) => {
      if (c2.req.path === "/health" || c2.req.path === "/api/events") {
        await next();
        return;
      }
      const apiKey = c2.req.header("x-api-key") || c2.req.header("authorization")?.replace("Bearer ", "") || c2.req.query("api_key");
      if (!apiKey) {
        return c2.json({
          error: "Authentication required",
          message: "API key must be provided via x-api-key header, Authorization header, or api_key query parameter"
        }, 401);
      }
      if (apiKey !== config.auth.apiKey) {
        return c2.json({
          error: "Invalid API key",
          message: "The provided API key is not valid"
        }, 401);
      }
      await next();
    });
  }
  app.use("*", async (c2, next) => {
    if (["POST", "PUT", "PATCH"].includes(c2.req.method)) {
      const contentType = c2.req.header("content-type");
      if (!contentType?.includes("application/json") && !contentType?.includes("multipart/form-data") && !contentType?.includes("application/x-www-form-urlencoded")) {
        return c2.json({
          error: "Invalid content type",
          message: "Content-Type must be application/json for API requests"
        }, 400);
      }
    }
    await next();
  });
  app.use("*", async (c2, next) => {
    const contentLength = c2.req.header("content-length");
    if (contentLength && parseInt(contentLength) > 10 * 1024 * 1024) {
      return c2.json({
        error: "Request too large",
        message: "Request body exceeds maximum size of 10MB"
      }, 413);
    }
    await next();
  });
  app.use("*", async (c2, next) => {
    try {
      await next();
    } catch (error) {
      console.error("Server error:", error);
      if (error instanceof HTTPException) {
        return error.getResponse();
      }
      if (error instanceof Error) {
        if (error.message.includes("JSON")) {
          return c2.json({
            error: "Invalid JSON",
            message: "Request body contains invalid JSON"
          }, 400);
        }
        if (error.message.includes("timeout")) {
          return c2.json({
            error: "Request timeout",
            message: "The request took too long to process"
          }, 408);
        }
        if (error.message.includes("not found")) {
          return c2.json({
            error: "Not found",
            message: error.message
          }, 404);
        }
        return c2.json({
          error: "Internal server error",
          message: error.message
        }, 500);
      }
      return c2.json({
        error: "Unknown error",
        message: "An unknown error occurred"
      }, 500);
    }
  });
  app.use("*", async (c2, next) => {
    await next();
    c2.header("X-Content-Type-Options", "nosniff");
    c2.header("X-Frame-Options", "DENY");
    c2.header("X-XSS-Protection", "1; mode=block");
    c2.header("Referrer-Policy", "strict-origin-when-cross-origin");
    if (false) {}
  });
  app.use("*", async (c2, next) => {
    const startTime = Date.now();
    const requestId = `req_${startTime}_${Math.random().toString(36).substr(2, 9)}`;
    c2.set("requestId", requestId);
    c2.header("X-Request-ID", requestId);
    await next();
    const duration = Date.now() - startTime;
    console.log(`[${requestId}] ${c2.req.method} ${c2.req.path} - ${c2.res.status} (${duration}ms)`);
  });
}

